// SNS delivers the CloudWatch alarm data double-serialised:
// body (outer SNS envelope) → body.Message (inner CloudWatch JSON string).
// Handle the SubscriptionConfirmation type so Terraform apply doesn't
// accidentally trigger the SOC workflow during infrastructure setup.

const raw = $input.first().json;
const body = raw.body ?? raw;
const sns = typeof body === 'string' ? JSON.parse(body) : body;

// AWS sends a SubscriptionConfirmation before live notifications.
// Log it and stop — the bridge setup guide covers manual confirmation.
if (sns.Type === 'SubscriptionConfirmation') {
  console.log('SNS SubscriptionConfirmation received. Visit SubscribeURL to confirm:');
  console.log(sns.SubscribeURL);
  return [];
}

if (sns.Type !== 'Notification') {
  console.log('Unexpected SNS Type:', sns.Type);
  return [];
}

// Inner CloudWatch alarm payload is a JSON string inside sns.Message
const alarm = JSON.parse(sns.Message);
const dims = alarm.Trigger?.Dimensions ?? [];

const get = (name) => dims.find(d => d.name === name)?.value ?? 'unknown';

return [{
  json: {
    alarmName:   alarm.AlarmName,
    alarmState:  alarm.NewStateValue,
    stateReason: alarm.NewStateReason,
    stateTime:   alarm.StateChangeTime,
    accountId:   alarm.AWSAccountId,
    webAclName:  get('WebACL'),
    ruleName:    get('Rule'),
    awsRegion:   get('Region'),
    snsSubject:  sns.Subject,
    rawAlarm:    alarm,
  }
}];

const splunkResponse = $input.first().json;
const results = splunkResponse.results ?? [];

// Carry forward alarm context from earlier in the workflow
const alarmCtx = $('Parse SNS + CloudWatch Payload').first().json;

if (results.length === 0) {
  // No blocked events in Splunk yet (propagation lag) — use defaults
  return [{
    json: {
      ...alarmCtx,
      attackerIp:        'unknown (data not yet in Splunk)',
      totalBlocked:      'N/A',
      uniqueUriCount:    'N/A',
      targetedEndpoints: [],
      countries:         [],
      firstSeen:         'N/A',
      lastSeen:          'N/A',
      attackDuration:    'N/A',
      splunkHasData:     false,
    }
  }];
}

const top = results[0];
const endpoints = Array.isArray(top.targeted_endpoints)
  ? top.targeted_endpoints
  : [top.targeted_endpoints].filter(Boolean);
const countries = Array.isArray(top.countries)
  ? top.countries
  : [top.countries].filter(Boolean);

return [{
  json: {
    ...alarmCtx,
    attackerIp:        top['httpRequest.clientIp'] ?? top.clientIp ?? 'unknown',
    totalBlocked:      top.total_blocked,
    uniqueUriCount:    top.unique_uri_count,
    targetedEndpoints: endpoints,
    countries:         countries,
    firstSeen:         top.first_seen,
    lastSeen:          top.last_seen,
    attackDuration:    top.attack_duration,
    splunkHasData:     true,
  }
}];

// Merge the new attacker IP into the existing IPSet addresses.
// WAF requires all addresses to be in CIDR notation.
const ipSetResponse = $('Get WAF IP Set — Fetch Lock Token').first().json;
const splunkData    = $('Parse Splunk Attacker Data').first().json;

const lockToken      = ipSetResponse.LockToken;
const existingAddrs  = ipSetResponse.IPSet?.Addresses ?? [];
const attackerIp     = splunkData.attackerIp;

if (!attackerIp || attackerIp === 'unknown' || !attackerIp.match(/^\d+\.\d+\.\d+\.\d+$/)) {
  throw new Error(`Cannot block invalid IP address: '${attackerIp}'`);
}

const newCidr    = `${attackerIp}/32`;
const merged     = [...new Set([...existingAddrs, newCidr])];

return [{
  json: {
    lockToken,
    mergedAddresses: merged,
    blockedIp: newCidr,
    previousCount: existingAddrs.length,
    newCount: merged.length,
  }
}];
